mapper.select:
SELECT id, event_type, payload, status, retry_count, error_message, next_retry_at, created_at, updated_at
FROM rag_outbox_events
WHERE id = #{id}

mapper.update:
UPDATE rag_outbox_events
SET status = 'PUBLISHED',
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND status IN ('NEW', 'FAILED')

UPDATE rag_outbox_events
SET status = 'SUCCESS',
    error_message = NULL,
    updated_at = #{updatedAt}
WHERE id = #{id}
